410→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
411→  const monthlyProjectCount = useMemo(() => {
412→    if (history.length === 0) return 0;
413→
414→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
415→    const now = new Date();
416→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
417→
418→    // 1. Identifier la date de création (première analyse) de chaque domaine
419→    const projectCreationDates = new Map<string, Date>();
420→    
421→    history.forEach(h => {
422→        let hostname;
423→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
424→        
425→        const analysisDate = new Date(h.timestamp);
426→        
427→        if (!projectCreationDates.has(hostname)) {
428→            projectCreationDates.set(hostname, analysisDate);
429→        } else {
430→            // On garde la date la plus ancienne trouvée pour ce domaine
431→            if (analysisDate < projectCreationDates.get(hostname)!) {
432→                projectCreationDates.set(hostname, analysisDate);
433→            }
434→        }
435→    });
436→
437→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
438→    let count = 0;
439→    projectCreationDates.forEach((creationDate) => {
440→        if (creationDate >= billingCycleStart) {
441→            count++;
442→        }
443→    });
444→    
445→    return count;
446→  }, [history]);
