import { MonitoringSchedule, ScheduledScanHistory } from '../types/scheduling';
import { 
  getSchedules, addSchedule, updateSchedule, removeSchedule, 
  toggleSchedule, computeNextRun, getScheduledHistory, checkAndRunPendingScans 
} from '../services/scheduling';
```

Add new state variables after the existing ones (around line 50):
```typescript
const [schedules, setSchedules] = useState<MonitoringSchedule[]>([]);
const [scanHistory, setScanHistory] = useState<ScheduledScanHistory[]>([]);
const [showScheduleForm, setShowScheduleForm] = useState(false);
const [scheduleFrequency, setScheduleFrequency] = useState<ScheduleFrequency>('daily');
const [scheduleTime, setScheduleTime] = useState('08:00');
const [scheduleDayOfWeek, setScheduleDayOfWeek] = useState(1);
const [scheduleDayOfMonth, setScheduleDayOfMonth] = useState(1);
const [scheduleEmail, setScheduleEmail] = useState(false);
const [activeScheduleTab, setActiveScheduleTab] = useState<'schedules' | 'history'>('schedules');
```

Add a `useEffect` on mount to load schedules and run pending scans:
```typescript
useEffect(() => {
  setSchedules(getSchedules());
  setScanHistory(getScheduledHistory());
  // Check for pending scans
  const pending = checkAndRunPendingScans(onDeductCredits);
  if (pending.length > 0) {
    setSchedules(getSchedules()); // reload after runs
    setScanHistory(getScheduledHistory());
  }
}, []);
```

Insert a "Planification" section in the input form view (between lines 213-216, after the scan form's closing `</div>` but before the outer closing `</div>`). This section contains:

A. A collapsible "Planification automatique" card with:
   - Frequency selector: 3 toggle buttons (Quotidien/Hebdomadaire/Mensuel)
   - Time picker (input type="time")
   - Day selector (conditional: day-of-week for weekly, day-of-month for monthly)
   - Email notification toggle (UI only, with "(Backend a venir)" note)
   - "Planifier ce scan" button that calls `addSchedule()` with current `brandName`/`url`/`period` and schedule params
   - Costs note: "0 Gas additionnel" (scheduling is free, each execution costs 5 Gas)

B. A "Marques planifiees" grid showing schedule cards:
   - Each card shows brand name, URL, frequency badge (colored: green=daily, blue=weekly, amber=monthly)
   - "Prochaine execution" date/time display
   - Last run date/time
   - Pause/Resume toggle (using `toggleSchedule()`)
   - Delete button (using `removeSchedule()`)

C. A "Historique des scans automatiques" section with tabs:
   - Timeline view showing scheduled scan history entries
   - Each entry shows: date, brand, status (completed/failed/skipped icon), citations count, trend

Insert in the results view (after the CTA section around line 662) a compact "Planifier le suivi" button/card that opens the schedule form pre-filled with the current brand/URL.

### localStorage Keys
- `citedby_monitoring_schedules` -- Array of `MonitoringSchedule`
- `citedby_scheduled_scan_history` -- Array of `ScheduledScanHistory`

### Gas Credit Costs
- Scheduling configuration: **0 Gas** (free to set up)
- Each automated scan execution: **5 Gas** (same as manual scan, reuses `CREDIT_COST`)

### Navigation Changes
No new page; everything lives within the existing `ai-monitoring` view. No App.tsx routing changes needed.

